import { Component, OnInit } from '@angular/core';
import { CommonModule, CurrencyPipe } from '@angular/common';
import { MatTableModule, MatTableDataSource } from '@angular/material/table';
import { MatSortModule, MatSort } from '@angular/material/sort';
import { MatInputModule } from '@angular/material/input';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatProgressBarModule } from '@angular/material/progress-bar';
import { FormsModule } from '@angular/forms';
import { ViewChild } from '@angular/core';
import { ClientService } from '../../core/services/client.service';
import { Client } from '../../models/client.model';

@Component({
  selector: 'app-clients',
  standalone: true,
  imports: [
    CommonModule, CurrencyPipe, FormsModule,
    MatTableModule, MatSortModule, MatInputModule,
    MatButtonModule, MatIconModule, MatProgressBarModule
  ],
  templateUrl: './clients.component.html',
  styleUrls: ['./clients.component.scss']
})
export class ClientsComponent implements OnInit {
  @ViewChild(MatSort) sort!: MatSort;

  displayedColumns = ['name', 'country', 'creditLimit', 'totalOutstanding', 'averageDso', 'riskProfile', 'overdueCount', 'actions'];
  dataSource = new MatTableDataSource<Client>([]);
  searchTerm = '';
  loading = true;

  constructor(private clientService: ClientService) {}

  ngOnInit(): void {
    this.clientService.getAll().subscribe({
      next: (data) => { this.dataSource.data = data; this.loading = false; },
      error: () => { this.dataSource.data = MOCK_CLIENTS; this.loading = false; }
    });
    setTimeout(() => { this.dataSource.sort = this.sort; });
  }

  applyFilter(): void {
    this.dataSource.filter = this.searchTerm.trim().toLowerCase();
  }

  getRiskClass(r: string): string { return r.toLowerCase(); }
}

